   196→  FilterConfigProviderManager& filter_config_provider_manager_;
   197→  Server::Configuration::ServerFactoryContext& server_context_;
   198→  Upstream::ClusterManager& cluster_manager_;
   199→  FilterCtx& factory_context_;
   200→  const std::string& stats_prefix_;
