    23→template <class T> using FilterList = std::list<std::unique_ptr<T>>;
    24→
    25→// Shared helper for recording the latest filter used.
    26→template <class T>
    27→void recordLatestDataFilter(const typename FilterList<T>::iterator current_filter,
    28→                            T*& latest_filter, const FilterList<T>& filters) {
    29→  // If this is the first time we're calling onData, just record the current filter.
    30→  if (latest_filter == nullptr) {
    31→    latest_filter = current_filter->get();
    32→    return;
    33→  }
    34→
    35→  // We want to keep this pointing at the latest filter in the filter list that has received the
    36→  // onData callback. To do so, we compare the current latest with the *previous* filter. If they
    37→  // match, then we must be processing a new filter for the first time. We omit this check if we're
    38→  // the first filter, since the above check handles that case.
    39→  //
    40→  // We compare against the previous filter to avoid multiple filter iterations from resetting the
    41→  // pointer: If we just set latest to current, then the first onData filter iteration would
    42→  // correctly iterate over the filters and set latest, but on subsequent onData iterations
    43→  // we'd start from the beginning again, potentially allowing filter N to modify the buffer even
    44→  // though filter M > N was the filter that inserted data into the buffer.
    45→  if (current_filter != filters.begin() && latest_filter == std::prev(current_filter)->get()) {
    46→    latest_filter = current_filter->get();
    47→  }
    48→}
    49→
    50→} // namespace
    51→
    52→void ActiveStreamFilterBase::commonContinue() {
    53→  if (!canContinue()) {
    54→    ENVOY_STREAM_LOG(trace, "cannot continue filter chain: filter={}", *this,
    55→                     static_cast<const void*>(this));
    56→    return;
    57→  }
    58→
    59→  // Set ScopeTrackerScopeState if there's no existing crash context.
    60→  ScopeTrackedObjectStack encapsulated_object;
    61→  absl::optional<ScopeTrackerScopeState> state;
    62→  if (parent_.dispatcher_.trackedObjectStackIsEmpty()) {
    63→    restoreContextOnContinue(encapsulated_object);
    64→    state.emplace(&encapsulated_object, parent_.dispatcher_);
    65→  }
    66→
    67→  ENVOY_STREAM_LOG(trace, "continuing filter chain: filter={}", *this,
    68→                   static_cast<const void*>(this));
    69→  ASSERT(!canIterate(),
    70→         "Attempting to continue iteration while the IterationState is already Continue");
    71→  // If iteration has stopped for all frame types, set iterate_from_current_filter_ to true so the
    72→  // filter iteration starts with the current filter instead of the next one.
    73→  if (stoppedAll()) {
    74→    iterate_from_current_filter_ = true;
    75→  }
    76→  allowIteration();
    77→
    78→  // Only resume with do1xxHeaders() if we've actually seen 1xx headers.
    79→  if (has1xxHeaders()) {
    80→    continued_1xx_headers_ = true;
    81→    do1xxHeaders();
    82→    // If the response headers have not yet come in, don't continue on with
    83→    // headers and body. doHeaders expects request headers to exist.
    84→    if (!parent_.filter_manager_callbacks_.responseHeaders()) {
    85→      return;
    86→    }
    87→  }
    88→
    89→  // Make sure that we handle the zero byte data frame case. We make no effort to optimize this
    90→  // case in terms of merging it into a header only request/response. This could be done in the
    91→  // future.
    92→  if (!headers_continued_) {
    93→    headers_continued_ = true;
    94→    doHeaders(complete() && !bufferedData() && !hasTrailers());
    95→  }
